    String shortDateString(Calendar cal) {
        int month = cal.get(Calendar.MONTH) + 1;
        int day = cal.get(Calendar.DAY_OF_MONTH);
        return twoDigits(month) + "/" + twoDigits(day);
    }

    String fullDateString(Calendar cal, RagicBundle bundle) {
        return (cal.get(Calendar.YEAR) - 1911) + "年" +
                (cal.get(Calendar.MONTH) + 1) + "月" +
                cal.get(Calendar.DAY_OF_MONTH) + "日（" +
                (bundle.getString("weekdayOne" + (cal.get(Calendar.DAY_OF_WEEK) - 1))) + "）";
    }

    String twoDigits(int x) {
        return (x < 10 ? "0" : "") + x;
    }

